#pragma once

#include "ofMain.h"

// Qualisys QTM Real-Time (RT) protocol SDK
#include "RTProtocol.h"
#include "RTPacket.h"

#include <atomic>
#include <mutex>
#include <thread>

/*
 * ofxQTMRT
 *
 * openFrameworks addon wrapping the Qualisys QTM Real-Time (RT) protocol
 * (qualisys_cpp_sdk). API modelled after ofxNatNet so existing ofApp code
 * ports over with minimal changes:
 *
 *     qtm.setup("192.168.0.1");   // QTM server ip
 *     qtm.update();               // call once per frame (non-blocking)
 *     for (int i = 0; i < qtm.getNumRigidBody(); i++) { ... }
 *
 * A background thread owns the CRTProtocol connection, streams 6DOF + 3D
 * marker data, and fills a back buffer. update() swaps it into the front
 * buffer so the main/draw thread reads lock-free.
 *
 * Units are millimetres by default (QTM native). Use setScale()/setTransform()
 * to convert, identical to ofxNatNet.
 */
class ofxQTMRT
{
public:
	typedef ofVec3f Marker;

	class RigidBody
	{
		friend class ofxQTMRT;

	public:
		int id = -1;
		string name;
		ofMatrix4x4 matrix;             // full transform (already scaled/transformed)
		float residual = 0.0f;          // QTM 6DOF residual; <0 means body not tracked this frame

		inline bool isActive() const { return _active; }
		const ofMatrix4x4& getMatrix() const { return matrix; }
		ofVec3f getPosition() const { return matrix.getTranslation(); }

	private:
		bool _active = false;
		ofVec3f raw_position;           // unscaled position (mm)
	};

	ofxQTMRT();
	~ofxQTMRT();

	// serverIp: QTM host. basePort: QTM RT base port (default 22222).
	void setup(string serverIp, unsigned short basePort = 22222);
	void update();                      // swap buffers; call once per frame
	void dispose();                     // stop thread + disconnect

	bool isConnected() const;
	int  getFrameNumber() const { return frame_number; }
	float getDataRate() const;          // received frames per second (approx)

	void setScale(float v);             // uniform scale applied to all positions
	ofVec3f getScale() const;
	void setTransform(const ofMatrix4x4& m);
	const ofMatrix4x4& getTransform() const;

	// ---- 6DOF rigid bodies ----
	size_t getNumRigidBody() const;
	const RigidBody& getRigidBodyAt(int index) const;
	bool hasRigidBody(int id) const;
	bool getRigidBody(int id, RigidBody& RB) const;
	bool hasRigidBodyByName(const string& name) const;
	bool getRigidBodyByName(const string& name, RigidBody& RB) const;

	// ---- 3D markers ----
	size_t getNumMarker() const;                    // labeled markers (Get3DMarker)
	const Marker& getMarker(size_t index) const;
	size_t getNumUnlabeledMarker() const;           // Get3DNoLabelsMarker
	const Marker& getUnlabeledMarker(size_t index) const;

	// Escape hatch to the full SDK (advanced settings, discovery, etc).
	// Only touch this from the same context as the receive thread is NOT
	// running, or guard your own access; intended for setup-time queries.
	CRTProtocol& getProtocol() { return rtProtocol; }

	void debugDraw();                   // markers + rigidbody axes (in cam space)

private:
	ofxQTMRT(const ofxQTMRT&);
	ofxQTMRT& operator=(const ofxQTMRT&);

	// data filled by receive thread, read by main thread after swap
	struct Frame
	{
		int frame_number = 0;
		vector<RigidBody> rigidbodies;
		vector<Marker> markers;
		vector<Marker> unlabeled_markers;
	};

	void threadFunction();
	void buildRigidBody(const string& name, float x, float y, float z,
						const float rot[9], float residual, RigidBody& out) const;

	CRTProtocol rtProtocol;
	string server_ip;
	unsigned short base_port = 22222;

	std::thread thread;
	std::atomic<bool> running{ false };
	std::atomic<bool> connected{ false };

	mutable std::mutex mutex;           // guards back_frame
	Frame back_frame;                   // written by thread
	Frame front_frame;                  // read by main thread (after update())

	// index maps (front buffer)
	map<int, int> id_to_index;
	map<string, int> name_to_index;

	int frame_number = 0;
	float scale = 1.0f;
	ofMatrix4x4 transform;

	// data-rate estimate
	float data_rate = 0.0f;
	float last_update_time = 0.0f;
	int last_frame_number = 0;
};

