//--------------------------------------------------------------
void ofApp::setup()
{
	ofSetFrameRate(60);
	ofSetVerticalSync(true);
	ofBackground(0);

	// QTM server ip. Base RT port is 22222 by default.
	qtm.setup("127.0.0.1");

	// QTM streams in millimetres. Scale here if you prefer other units.
	// qtm.setScale(0.1); // -> centimetres
}

//--------------------------------------------------------------
void ofApp::update() { qtm.update(); }

//--------------------------------------------------------------
void ofApp::draw()
{
	ofEnableDepthTest();
	cam.begin();
	ofDrawAxis(100);

	ofFill();

	// labeled 3D markers
	ofSetColor(255, 200);
	for (size_t i = 0; i < qtm.getNumMarker(); i++)
		ofDrawBox(qtm.getMarker(i), 8);

	// unlabeled 3D markers
	ofSetColor(255, 60);
	for (size_t i = 0; i < qtm.getNumUnlabeledMarker(); i++)
		ofDrawBox(qtm.getUnlabeledMarker(i), 8);

	// 6DOF rigid bodies
	for (size_t i = 0; i < qtm.getNumRigidBody(); i++)
	{
		const ofxQTMRT::RigidBody& RB = qtm.getRigidBodyAt(i);

		ofPushMatrix();
		ofMultMatrix(RB.getMatrix());
		ofDrawAxis(60);
		ofSetColor(RB.isActive() ? ofColor(0, 255, 0) : ofColor(255, 0, 0));
		ofDrawBitmapString(ofToString(RB.id) + ":" + RB.name, 0, 10);
		ofPopMatrix();
	}

	cam.end();
	ofDisableDepthTest();

	string str;
	str += "fps: " + ofToString(ofGetFrameRate(), 1) + "\n";
	str += string("connected: ") + (qtm.isConnected() ? "YES" : "NO") + "\n";
	str += "frame: " + ofToString(qtm.getFrameNumber()) + "\n";
	str += "data rate: " + ofToString(qtm.getDataRate(), 1) + "\n";
	str += "rigid bodies: " + ofToString(qtm.getNumRigidBody()) + "\n";
	str += "labeled markers: " + ofToString(qtm.getNumMarker()) + "\n";
	str += "unlabeled markers: " + ofToString(qtm.getNumUnlabeledMarker()) + "\n";

	ofSetColor(255);
	ofDrawBitmapString(str, 10, 20);
}

//--------------------------------------------------------------
void ofApp::keyPressed(int key) {}

