#include "tcApp.h"

void tcApp::setup() {
    setWindowTitle("tcxQTMRT - qtmrt2osc bridge");

    qtm.setup("127.0.0.1");      // QTM server ip
    osc.setup(oscHost, oscPort); // OSC destination
}

void tcApp::update() {
    qtm.update();

    // forward only when a new QTM frame arrived
    int frame = qtm.getFrameNumber();
    if (frame == lastSentFrame) return;
    lastSentFrame = frame;

    for (size_t i = 0; i < qtm.getNumRigidBody(); i++) {
        const auto& rb = qtm.getRigidBodyAt(i);
        if (!rb.isActive()) continue;

        const Mat4& M = rb.getMatrix();
        Vec3 p = rb.getPosition();

        tcx::OscMessage m;
        m.setAddress("/qtm/rigidbody");
        m.addInt(rb.id);
        m.addString(rb.name);
        m.addFloat(p.x);
        m.addFloat(p.y);
        m.addFloat(p.z);
        // 3x3 rotation basis (row-major: m0..m8)
        m.addFloat(M.m[0]); m.addFloat(M.m[1]); m.addFloat(M.m[2]);
        m.addFloat(M.m[4]); m.addFloat(M.m[5]); m.addFloat(M.m[6]);
        m.addFloat(M.m[8]); m.addFloat(M.m[9]); m.addFloat(M.m[10]);

        osc.send(m);
        sentMessages++;
    }
}

void tcApp::draw() {
    clear(0.07f, 0.07f, 0.09f);

    string info;
    info += "QTM -> OSC bridge\n\n";
    info += string("QTM connected: ") + (qtm.isConnected() ? "YES" : "NO") + "\n";
    info += "QTM frame: " + to_string(qtm.getFrameNumber()) + "\n";
    info += "rigid bodies: " + to_string(qtm.getNumRigidBody()) + "\n\n";
    info += "OSC dest: " + oscHost + ":" + to_string(oscPort) + "\n";
    info += "OSC messages sent: " + to_string(sentMessages) + "\n";

    setColor(1.0f);
    drawBitmapString(info, 20, 20);
}

